(1, 1, '2026-03-30 09:38:22', '2026-03-30 09:38:22', '<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->', 'Hello world!', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2026-03-30 09:38:22', '2026-03-30 09:38:22', '', 0, 'http://localhost/wordpress/?p=1', 0, 'post', '', 1),
(2, 1, '2026-03-30 09:38:22', '2026-03-30 09:38:22', '<!-- wp:paragraph -->\n<p>This is an example page. It\'s different from a blog post because it will stay in one place and will show up in your site navigation (in most themes). Most people start with an About page that introduces them to potential site visitors. It might say something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Hi there! I\'m a bike messenger by day, aspiring actor by night, and this is my website. I live in Los Angeles, have a great dog named Jack, and I like pi&#241;a coladas. (And gettin\' caught in the rain.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>...or something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>The XYZ Doohickey Company was founded in 1971, and has been providing quality doohickeys to the public ever since. Located in Gotham City, XYZ employs over 2,000 people and does all kinds of awesome things for the Gotham community.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>As a new WordPress user, you should go to <a href=\"http://localhost/wordpress/wp-admin/\">your dashboard</a> to delete this page and create new pages for your content. Have fun!</p>\n<!-- /wp:paragraph -->', 'Sample Page', '', 'publish', 'closed', 'open', '', 'sample-page', '', '', '2026-03-30 09:38:22', '2026-03-30 09:38:22', '', 0, 'http://localhost/wordpress/?page_id=2', 0, 'page', '', 0),
(4, 0, '2026-03-30 09:38:23', '2026-03-30 09:38:23', '', 'Navigation', '', 'publish', 'closed', 'closed', '', 'navigation', '', '', '2026-04-02 09:57:17', '2026-04-02 09:57:17', '', 0, 'http://localhost/wordpress/index.php/2026/03/30/navigation/', 0, 'wp_navigation', '', 0),
(7, 1, '2026-03-30 09:51:26', '2026-03-30 09:51:26', '{\"styles\":{\"background\":{\"backgroundImage\":{\"url\":\"http:\\/\\/localhost\\/wordpress\\/wp-content\\/uploads\\/2026\\/03\\/BACKGROUND-scaled.jpg\",\"id\":29,\"source\":\"file\",\"title\":\"BACKGROUND\"},\"backgroundPosition\":\"50% 48%\",\"backgroundSize\":\"auto\",\"backgroundAttachment\":\"fixed\"},\"spacing\":{\"padding\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"},\"blockGap\":\"1.4rem\"}},\"settings\":{\"shadow\":{\"presets\":{\"default\":[{\"name\":\"Natural\",\"slug\":\"natural\",\"shadow\":\"6px 6px 9px rgba(0, 0, 0, 0.2)\"},{\"name\":\"Deep\",\"slug\":\"deep\",\"shadow\":\"12px 12px 50px rgba(0, 0, 0, 0.4)\"},{\"name\":\"Sharp\",\"slug\":\"sharp\",\"shadow\":\"6px 6px 0px rgba(0, 0, 0, 0.2)\"},{\"name\":\"Outlined\",\"slug\":\"outlined\",\"shadow\":\"6px 6px 0px -3px rgb(255, 255, 255)\"},{\"name\":\"Crisp\",\"slug\":\"crisp\",\"shadow\":\"6px 6px 0px rgb(0, 0, 0)\"}]}}},\"isGlobalStylesUserThemeJSON\":true,\"version\":3}', 'Custom Styles', '', 'publish', 'closed', 'closed', '', 'wp-global-styles-pro-portfolio', '', '', '2026-04-02 09:48:34', '2026-04-02 09:48:34', '', 0, 'http://localhost/wordpress/index.php/2026/03/30/wp-global-styles-pro-portfolio/', 0, 'wp_global_styles', '', 0);
