(8, 1, '2026-03-30 10:11:26', '2026-03-30 10:11:26', '<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"pro-portfolio\",\"tagName\":\"header\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"align\":\"full\",\"className\":\"has-no-underline\",\"style\":{\"spacing\":{\"blockGap\":\"0\",\"padding\":{\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group alignfull has-no-underline\" style=\"margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:0;padding-left:0\"></main>\n<!-- /wp:group -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"tagName\":\"main\",\"align\":\"full\",\"className\":\"has-no-underline\",\"style\":{\"spacing\":{\"blockGap\":\"0\",\"padding\":{\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group alignfull has-no-underline\" style=\"margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:0;padding-left:0\"><!-- wp:group {\"tagName\":\"section\",\"metadata\":{\"name\":\"Banner Section\"},\"align\":\"full\",\"className\":\"banner-section\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"30px\",\"left\":\"30px\",\"top\":\"var:preset|spacing|60\",\"bottom\":\"0\"},\"blockGap\":\"0\"},\"border\":{\"radius\":{\"topLeft\":\"100px\",\"topRight\":\"100px\",\"bottomLeft\":\"100px\",\"bottomRight\":\"100px\"},\"width\":\"0px\",\"style\":\"none\"}},\"backgroundColor\":\"black\",\"layout\":{\"type\":\"constrained\"}} -->\n<section class=\"wp-block-group alignfull banner-section has-black-background-color has-background\" style=\"border-style:none;border-width:0px;border-top-left-radius:100px;border-top-right-radius:100px;border-bottom-left-radius:100px;border-bottom-right-radius:100px;padding-top:var(--wp--preset--spacing--60);padding-right:30px;padding-bottom:0;padding-left:30px\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"align\":\"wide\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"padding\":{\"right\":\"0\",\"left\":\"0\",\"top\":\"0\",\"bottom\":\"5rem\"},\"blockGap\":{\"top\":\"0\",\"left\":\"0\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|border\",\"width\":\"1px\"}}}} -->\n<div class=\"wp-block-columns alignwide are-vertically-aligned-center\" style=\"border-bottom-color:var(--wp--preset--color--border);border-bottom-width:1px;margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:5rem;padding-left:0\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":\"0px\",\"padding\":{\"top\":\"55px\",\"right\":\"0px\",\"bottom\":\"55px\",\"left\":\"0px\"}}},\"layout\":{\"inherit\":false,\"wideSize\":\"1500px\"}} -->\n<div class=\"wp-block-group alignwide\" style=\"padding-top:55px;padding-right:0px;padding-bottom:55px;padding-left:0px\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":3,\"style\":{\"typography\":{\"lineHeight\":\"1.5\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"5px\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\",\"fontSize\":\"normal\"} -->\n<h3 class=\"wp-block-heading has-text-align-left has-boulder-color has-text-color has-link-color has-normal-font-size\" style=\"letter-spacing:5px;line-height:1.5;text-transform:uppercase\">Welcome to my world</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"left\",\"style\":{\"typography\":{\"lineHeight\":\"1.2\",\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"spacing\":{\"margin\":{\"bottom\":\"var:preset|spacing|50\",\"top\":\"var:preset|spacing|50\"}}},\"textColor\":\"primary\",\"fontSize\":\"extra-large\"} -->\n<h2 class=\"wp-block-heading has-text-align-left has-primary-color has-text-color has-extra-large-font-size\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50);font-style:normal;font-weight:700;line-height:1.2\">Hi, I’m&nbsp;Sayan<br>a&nbsp;<strong>Web devoloper.</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\"} -->\n<p class=\"has-text-align-left has-boulder-color has-text-color has-link-color\">Creative web developer passionate about building responsive websites, optimizing performance, improving user experience, and delivering modern, efficient digital solutions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"className\":\" animated animated-fadeInUp\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"20px\",\"bottom\":\"0px\"},\"blockGap\":\"20px\"}},\"layout\":{\"type\":\"flex\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-buttons animated animated-fadeInUp\" style=\"margin-top:20px;margin-bottom:0px\"><!-- wp:button {\"textColor\":\"primary\",\"className\":\"is-style-fill\",\"style\":{\"color\":{\"gradient\":\"linear-gradient(145deg,rgb(226,232,236) 0%,rgb(255,255,255) 100%)\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|primary\"}}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"700\"},\"shadow\":\"var:preset|shadow|natural\",\"border\":{\"radius\":\"10px\",\"top\":{\"color\":\"var:preset|color|background-secondary\",\"width\":\"2px\"},\"right\":{\"color\":\"#ffffff00\",\"width\":\"2px\"},\"bottom\":{\"color\":\"#ffffff00\",\"width\":\"2px\"},\"left\":{\"color\":\"var:preset|color|background-secondary\",\"width\":\"2px\"}}}} -->\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link has-primary-c