(15, 1, '2026-03-30 10:42:45', '2026-03-30 10:42:45', '<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"pro-portfolio\",\"tagName\":\"header\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"align\":\"full\",\"className\":\"has-no-underline\",\"style\":{\"spacing\":{\"blockGap\":\"0\",\"padding\":{\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"},\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group alignfull has-no-underline\" style=\"margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:0;padding-left:0\"><!-- wp:group {\"tagName\":\"section\",\"metadata\":{\"name\":\"Banner Section\"},\"align\":\"full\",\"className\":\"banner-section\",\"style\":{\"spacing\":{\"padding\":{\"right\":\"30px\",\"left\":\"30px\",\"top\":\"var:preset|spacing|60\",\"bottom\":\"0\"}}},\"backgroundColor\":\"black\",\"layout\":{\"type\":\"constrained\"}} -->\n<section class=\"wp-block-group alignfull banner-section has-black-background-color has-background\" style=\"padding-top:var(--wp--preset--spacing--60);padding-right:30px;padding-bottom:0;padding-left:30px\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"align\":\"wide\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"padding\":{\"right\":\"0\",\"left\":\"0\",\"top\":\"0\",\"bottom\":\"5rem\"},\"blockGap\":{\"top\":\"0\",\"left\":\"0\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|border\",\"width\":\"1px\"}}}} -->\n<div class=\"wp-block-columns alignwide are-vertically-aligned-center\" style=\"border-bottom-color:var(--wp--preset--color--border);border-bottom-width:1px;margin-top:0;margin-bottom:0;padding-top:0;padding-right:0;padding-bottom:5rem;padding-left:0\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":\"0px\",\"padding\":{\"top\":\"55px\",\"right\":\"0