shadow|sharp\"},\"layout\":{\"inherit\":true,\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignwide has-style-box-shadow has-background\" style=\"border-top-left-radius:55px;border-top-right-radius:55px;border-bottom-left-radius:55px;border-bottom-right-radius:55px;border-top-color:#FFFFFF;border-top-width:2px;border-right-color:#ffffff00;border-right-width:2px;border-bottom-color:#ffffff00;border-bottom-width:2px;border-left-color:#FFFFFF;border-left-width:2px;background:linear-gradient(140deg,rgb(226,232,236) 0%,rgb(255,255,255) 100%);padding-top:30px;padding-right:30px;padding-bottom:30px;padding-left:30px;box-shadow:var(--wp--preset--shadow--sharp)\"><!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"10px\"}},\"layout\":{\"inherit\":false}} -->\n<div class=\"wp-block-group\"><!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\",\"justifyContent\":\"space-between\"}} -->\n<div class=\"wp-block-group\"><!-- wp:group {\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"blockGap\":\"0\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:0;margin-bottom:0\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":3,\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\"},\"padding\":{\"top\":\"0\",\"bottom\":\"0\"}},\"typography\":{\"fontStyle\":\"normal\",\"fontWeight\":\"500\"},\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|foreground\"}}}},\"textColor\":\"foreground\",\"fontSize\":\"medium\"} -->\n<h3 class=\"wp-block-heading has-text-align-left has-foreground-color has-text-color has-link-color has-medium-font-size\" style=\"margin-top:0;margin-right:0;margin-bottom:0;margin-left:0;padding-top:0;padding-bottom:0;font-style:normal;font-weight:500\">Weather App</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\"} -->\n<p class=\"has-text-align-left has-boulder-color has-text-color has-link-color\"></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"var:preset|spacing|50\",\"bottom\":\"var:preset|spacing|50\"}}},\"backgroundColor\":\"border\"} -->\n<hr class=\"wp-block-separator has-text-color has-border-color has-alpha-channel-opacity has-border-background-color has-background is-style-wide\" style=\"margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--50)\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|boulder\"}}}},\"textColor\":\"boulder\"} -->\n<p class=\"has-text-align-left has-boulder-color has-text-color has-link-color\">I develop weather applications that provide real-time forecasts, location-based updates, temperature details, and intuitive user interfaces for accurate and easy weather monitoring.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group --></main>\n<!-- /wp:group -->', 'Front Page', 'Displays your site\'s homepage, whether it is set to display latest posts or a static page. The Front Page template takes precedence over all templates.', 'inherit', 'closed', 'closed', '', '8-revision-v1', '', '', '2026-04-02 09:48:08', '2026-04-02 09:48:08', '', 8, 'http://localhost/wordpress/?p=48', 0, 'revision', '', 0);
