(49, 1, '2026-04-02 09:48:34', '2026-04-02 09:48:34', '{\"styles\":{\"background\":{\"backgroundImage\":{\"url\":\"http:\\/\\/localhost\\/wordpress\\/wp-content\\/uploads\\/2026\\/03\\/BACKGROUND-scaled.jpg\",\"id\":29,\"source\":\"file\",\"title\":\"BACKGROUND\"},\"backgroundPosition\":\"50% 48%\",\"backgroundSize\":\"auto\",\"backgroundAttachment\":\"fixed\"},\"spacing\":{\"padding\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"},\"blockGap\":\"1.4rem\"}},\"settings\":{\"shadow\":{\"presets\":{\"default\":[{\"name\":\"Natural\",\"slug\":\"natural\",\"shadow\":\"6px 6px 9px rgba(0, 0, 0, 0.2)\"},{\"name\":\"Deep\",\"slug\":\"deep\",\"shadow\":\"12px 12px 50px rgba(0, 0, 0, 0.4)\"},{\"name\":\"Sharp\",\"slug\":\"sharp\",\"shadow\":\"6px 6px 0px rgba(0, 0, 0, 0.2)\"},{\"name\":\"Outlined\",\"slug\":\"outlined\",\"shadow\":\"6px 6px 0px -3px rgb(255, 255, 255)\"},{\"name\":\"Crisp\",\"slug\":\"crisp\",\"shadow\":\"6px 6px 0px rgb(0, 0, 0)\"}]}}},\"isGlobalStylesUserThemeJSON\":true,\"version\":3}', 'Custom Styles', '', 'inherit', 'closed', 'closed', '', '7-revision-v1', '', '', '2026-04-02 09:48:34', '2026-04-02 09:48:34', '', 7, 'http://localhost/wordpress/?p=49', 0, 'revision', '', 0),
(50, 1, '2026-04-02 09:52:50', '2026-04-02 09:52:50', '<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|background\"}}},\"border\":{\"radius\":{\"topLeft\":\"55px\",\"topRight\":\"55px\",\"bottomLeft\":\"55px\",\"bottomRight\":\"55px\"}}},\"backgroundColor\":\"foreground\",\"textColor\":\"background\",\"fontSize\":\"large\"} -->\n<p class=\"has-background-color has-foreground-background-color has-text-color has-background has-link-color has-large-font-size\" style=\"border-top-left-radius:55px;border-top-right-radius:55px;border-bottom-left-radius:55px;border-bottom-right-radius:55px\">Why Choose Me</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|background\"}}},\"border\":{\"radius\":{\"topLeft\":\"55px\",\"topRight\":\"55px\",\"bottomLeft\":\"55px\",\"bottomRight\":\"55px\"}}},\"backgroundColor\":\"foreground\",\"textColor\":\"background\",\"fontSize\":\"medium\"} -->\n<p class=\"has-background-color has-foreground-background-color has-text-color has-background has-link-color has-medium-font-size\" style=\"border-top-left-radius:55px;border-top-right-radius:55px;border-bottom-left-radius:55px;border-bottom-right-radius:55px\">I build modern, responsive, and user-friendly websites focused on performance and clean design. As a passionate web developer, I transform ideas into functional web applications using modern technologies. My Advanced Weather App project demonstrates my ability to develop real-world, dynamic applications with interactive UI and real-time data integration.</p>\n<!-- /wp:paragraph -->', 'Containt', '', 'publish', 'closed', 'closed', '', 'containt', '', '', '2026-04-02 10:34:00', '2026-04-02 10:34:00', '', 0, 'http://localhost/wordpress/?page_id=50', 0, 'page', '', 0),
(51, 1, '2026-04-02 09:52:50', '2026-04-02 09:52:50', '<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|background\"}}},\"border\":{\"radius\":{\"topLeft\":\"55px\",\"topRight\":\"55px\",\"bottomLeft\":\"55px\",\"bottomRight\":\"55px\"}}},\"backgroundColor\":\"foreground\",\"textColor\":\"background\",\"fontSize\":\"large\"} -->\n<p class=\"has-background-color has-foreground-background-color has-text-color has-background has-link-color has-large-font-size\" style=\"border-top-left-radius:55px;border-top-right-radius:55px;border-bottom-left-radius:55px;border-bottom-right-radius:55px\">Why you chouse</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|background\"}}},\"border\":{\"radius\":{\"topLeft\":\"55px\",\"topRight\":\"55px\",\"bottomLeft\":\"55px\",\"bottomRight\":\"55px\"}}},\"backgroundColor\":\"foreground\",\"textColor\":\"background\",\"fontSize\":\"medium\"} -->\n<p class=\"has-background-color has-foreground-background-color has-text-color has-background has-link-color has-medium-font-size\" style=\"border-top-left-radius:55px;border-top-right-radius:55px;border-bottom-left-radius:55px;border-bottom-right-radius:55px\">I chose web development because it combines creativity, problem-solving, and technology to build real-world digital solutions. I enjoy designing and developing websites that are interactive, user-friendly, and functional. Web development allows me to transform ideas into live applications while continuously learning modern technologies, programming languages, and frameworks. As a BCA student, I am passionate about creating responsive websites and improving user experiences through clean design and efficient coding.</p>\n<!-- /wp:paragraph -->', 'Containt', '', 'inherit', 'closed', 'closed', '', '50-revision-v1', '', '', '2026-04-02 09:52:50', '2026-04-02 09:52:50', '', 50, 'http://localhost/wordpress/?p=51', 0, 'revision', '', 0);
