:\"boulder\"} -->\n<p class=\"has-text-align-left has-boulder-color has-background-background-color has-text-color has-background has-link-color\">Currently pursuing Bachelor of Computer Applications (BCA) with focus on programming, web development, databases, and modern software technologies. Developing practical skills in software development, problem-solving, and application design through academic projects and hands-on learning.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"border\":{\"left\":{\"color\":\"var:preset|color|primary\",\"width\":\"6px\"},\"top\":[],\"right\":[],\"bottom\":[]},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"},\"padding\":{\"left\":\"var:preset|spacing|50\",\"top\":\"var:preset|spacing|50\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\" style=\"border-left-color:var(--wp--preset--color--primary);border-left-width:6px;margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--50);padding-left:var(--wp--preset--spacing--50)\"></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></section>\n<!-- /wp:group -->\n\n<!-- wp:group {\"tagName\":\"section\",\"metadata\":{\"name\":\"Testimonial Section\"},\"align\":\"full\",\"className\":\"testimonial\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"right\":\"30px\",\"left\":\"30px\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<section class=\"wp-block-group alignfull testimonial\" style=\"padding-top:5rem;padding-right:30px;padding-bottom:0;padding-left:30px\"><!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"padding\":{\"bottom\":\"5rem\"}},\"border\":{\"bottom\":{\"color\":\"var:preset|color|border\",\"width\":\"1px\"},\"top\":[],\"right\":[],\"left\":[]}},\"layout\":{\"type\":\"constrained